    saveTransaction: function(e) {
        e.preventDefault();
        const form = e.target;
        const amount = parseFloat(form.amount.value);
        const date = form.date.value;
        const desc = (form.description.value || '').toLowerCase();
        const type = form.type.value;

        // Check for duplicates
        const purchases = store.state.purchases || [];
        const sales = store.state.sales || [];
        const allTransactions = [...purchases.map(p => ({
            amount: p.amount || p.total_amount || 0,
            date: (p.date || p.purchase_date || p.created_at || '').split('T')[0],
            desc: (p.description || p.item || '').toLowerCase()
        })), ...sales.map(s => ({
            amount: s.sale_price || 0,
            date: (s.created_at || '').split('T')[0],
            desc: (s.listing_title || s.inventory_title || '').toLowerCase()
        }))];

        const duplicate = allTransactions.find(t =>
            Math.abs(t.amount - amount) < 0.01 && t.date === date
        );

        if (duplicate && !store.state._txDuplicateConfirmed) {
            const warningHtml = `
                <div style="background: var(--warning-50, #fff8e1); border: 1px solid var(--warning-300, #ffcc02); border-radius: 8px; padding: 12px; margin-bottom: 16px;">
                    <div style="font-weight: 600; color: var(--warning-700, #7a5900); margin-bottom: 4px;">
                        ${components.icon('alert-triangle', 16)} Possible Duplicate Detected
                    </div>
                    <div style="font-size: 13px; color: var(--warning-600, #946800);">
                        A transaction with the same amount ($${amount.toFixed(2)}) on the same date (${date}) already exists.
                    </div>
                </div>
            `;
            const warningEl = form.querySelector('.tx-duplicate-warning');
            if (!warningEl) {
                form.insertAdjacentHTML('afterbegin', '<div class="tx-duplicate-warning">' + warningHtml + '</div>');
                const submitBtn = form.querySelector('button[type="submit"]');
                if (submitBtn) submitBtn.textContent = 'Add Anyway';
                store.setState({ _txDuplicateConfirmed: true });
                return;
            }
        }

        store.setState({ _txDuplicateConfirmed: false });
        toast.success('Transaction added');
        modals.close();
        renderApp(pages.transactions());
    },

