    // What-If Scenario handler
    runWhatIfScenario: function() {
        const priceChange = parseInt(document.getElementById('whatif-price-change')?.value || 0);
        const category = document.getElementById('whatif-category')?.value || 'all';
        const period = parseInt(document.getElementById('whatif-period')?.value || 30);

        store.setState({ whatIfPriceChange: priceChange });

        toast.info('Running scenario analysis...');
        setTimeout(() => {
            const baseRevenue = store.state.sales?.reduce((sum, s) => sum + (s.sale_price || 0), 0) || 2500;
            const baseSales = store.state.sales?.length || 25;
            const revenueMultiplier = 1 + (priceChange / 100);
            const demandImpact = priceChange > 0 ? 1 - (priceChange / 200) : 1 + (Math.abs(priceChange) / 150);
            const projectedSales = Math.round(baseSales * demandImpact * (period / 30));
            const projectedRevenue = Math.round(baseRevenue * revenueMultiplier * demandImpact * (period / 30));
            const baseDays = 12;
            const daysToSell = Math.max(1, Math.round(baseDays * (priceChange > 0 ? 1 + priceChange / 50 : 1 - Math.abs(priceChange) / 80)));
            const profitImpact = Math.round((revenueMultiplier * demandImpact - 1) * 100);

            store.setState({
                whatIfResults: {
                    revenue: projectedRevenue.toLocaleString(),
                    sales: projectedSales,
                    daysToSell: daysToSell,
                    profitImpact: profitImpact
                }
            });
            toast.success('Scenario analysis complete');
            renderApp(pages.predictions());
        }, 800);
    },

    // Prediction Details modal (enhanced)
    showPredictionDetails: function(id) {
        const predictions = store.state.predictions || [];
        const pred = predictions.find(p => p.id === id);
        const displayPred = pred || {
            item_title: 'Sample Item', current_price: 50, predicted_price: 62,
            confidence: 78, demand_score: 'High', recommendation: 'Buy'
        };
        const change = displayPred.predicted_price - displayPred.current_price;
        const pct = ((change / (displayPred.current_price || 1)) * 100).toFixed(1);
        const isUp = change >= 0;
        const pessimistic = Math.round(displayPred.predicted_price * 0.82);
        const optimistic = Math.round(displayPred.predicted_price * 1.22);

        modals.show(`
            <div class="modal-header">
                <h2 class="modal-title">${components.icon('zap', 20)} Prediction Details</h2>
                <button class="modal-close" aria-label="Close" onclick="modals.close()">${components.icon('x', 20)}</button>
            </div>
            <div class="modal-body">
                <h3 class="font-semibold mb-3">${escapeHtml(displayPred.item_title || 'Item')}</h3>
                <div class="grid grid-cols-3 gap-3 mb-4">
                    <div style="text-align: center; padding: 12px; background: var(--gray-50); border-radius: 8px;">
                        <div class="text-xs text-gray-500">Current</div>
                        <div class="text-xl font-bold">$${(displayPred.current_price || 0).toFixed(0)}</div>
                    </div>
                    <div style="text-align: center; padding: 12px; background: var(--primary-50); border-radius: 8px;">
                        <div class="text-xs text-gray-500">Predicted</div>
                        <div class="text-xl font-bold" style="color: var(--primary);">$${(displayPred.predicted_price || 0).toFixed(0)}</div>
                    </div>
                    <div style="text-align: center; padding: 12px; background: ${isUp ? 'var(--success-50)' : 'var(--error-50)'}; border-radius: 8px;">
                        <div class="text-xs text-gray-500">Change</div>
                        <div class="text-xl font-bold" style="color: ${isUp ? 'var(--success)' : 'var(--error)'};">${isUp ? '+' : ''}${pct}%</div>
                    </div>
                </div>
                <div class="mb-4">
                    <div class="text-sm font-semibold mb-2">Price Range Scenarios</div>
                    <div style="display: flex; gap: 8px; align-items: center;">
                        <span class="text-xs" style="color: var(--error);">$${pessimistic}</span>
                        <div style="flex: 1; height: 8px; background: linear-gradient(90deg, var(--error), var(--primary), var(--success)); border-radius: 4px;"></div>
                        <span class="text-xs" style="color: var(--success);">$${optimistic}</span>
                    </div>
                </div>
                <div style="padding: 12px; background: var(--primary-50); border-radius: 8px;">
                    <div class="text-sm font-semibold mb-1">AI Analysis</div>
                    <p class="text-xs text-gray-600">
                        ${isUp
                            ? `This item shows strong upward price momentum. Market demand is ${displayPred.demand_score || 'moderate'} with limited competing supply. Seasonal trends are favorable for the next 30 days.`
                            : `Market conditions suggest softening demand. Consider strategic pricing to maintain sales velocity. Monitor competitor pricing for potential market shifts.`
                        }
                    </p>
                </div>
            </div>
            <div class="modal-footer">
                <button class="btn btn-secondary" onclick="modals.close()">Close</button>
            </div>
        `);
    },

