    viewInsightDetails: function(id) {
        const insights = store.state.marketInsights || [];
        const insight = insights.find(i => i.id === id) || {};
        const title = insight.title || insight.name || 'Market Insight';
        const category = insight.category || 'General';
        const trend = insight.trend || 'stable';
        const trendIcon = trend === 'up' ? 'trendUp' : trend === 'down' ? 'trendDown' : 'minus';
        const trendColor = trend === 'up' ? 'var(--success)' : trend === 'down' ? 'var(--danger)' : 'var(--gray-500)';
        const confidence = insight.confidence || insight.score || 75;
        const description = insight.description || insight.summary || 'No additional details available.';
        const source = insight.source || insight.platform || 'Multiple Sources';

        modals.show(`
            <div class="modal-header">
                <h2 class="modal-title">${components.icon('trendUp', 20)} ${escapeHtml(title)}</h2>
                <button class="modal-close" aria-label="Close" onclick="modals.close()">${components.icon('close')}</button>
            </div>
            <div class="modal-body">
                <div style="display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 12px; margin-bottom: 20px;">
                    <div style="background: var(--gray-50); padding: 12px; border-radius: 8px; text-align: center;">
                        <div style="font-size: 12px; color: var(--gray-500);">Category</div>
                        <div style="font-weight: 600; margin-top: 4px;">${escapeHtml(category)}</div>
                    </div>
                    <div style="background: var(--gray-50); padding: 12px; border-radius: 8px; text-align: center;">
                        <div style="font-size: 12px; color: var(--gray-500);">Trend</div>
                        <div style="font-weight: 600; margin-top: 4px; color: ${trendColor};">${components.icon(trendIcon, 16)} ${trend.charAt(0).toUpperCase() + trend.slice(1)}</div>
                    </div>
                    <div style="background: var(--gray-50); padding: 12px; border-radius: 8px; text-align: center;">
                        <div style="font-size: 12px; color: var(--gray-500);">Confidence</div>
                        <div style="font-weight: 600; margin-top: 4px;">${confidence}%</div>
                    </div>
                </div>
                <div style="margin-bottom: 16px;">
                    <h4 style="margin-bottom: 8px; font-size: 14px; color: var(--gray-700);">Analysis</h4>
                    <p style="color: var(--gray-600); line-height: 1.6;">${escapeHtml(description)}</p>
                </div>
                <div style="background: var(--primary-50, #eff6ff); padding: 12px; border-radius: 8px; border-left: 3px solid var(--primary-600);">
                    <div style="font-size: 12px; font-weight: 600; color: var(--primary-700); margin-bottom: 4px;">Recommendation</div>
                    <p style="font-size: 13px; color: var(--primary-600);">${trend === 'up' ? 'Consider increasing inventory in this category to capture demand.' : trend === 'down' ? 'Reduce exposure and consider running promotions to move existing stock.' : 'Market is stable. Maintain current strategy and monitor for changes.'}</p>
                </div>
                <div style="margin-top: 12px; font-size: 12px; color: var(--gray-400);">Source: ${escapeHtml(source)} &middot; Updated: ${insight.updated_at ? new Date(insight.updated_at).toLocaleDateString() : 'Recently'}</div>
            </div>
        `);
    },

