    verifyMfaLogin: async function(e) {
        e.preventDefault();
        const code = e.target.code.value.trim();
        if (code.length !== 6) { toast.error('Please enter a 6-digit code'); return; }
        try {
            const data = await api.post('/auth/mfa-verify', {
                mfaToken: store.state.pendingMfaToken,
                code
            });
            store.setState({
                user: data.user,
                token: data.token,
                refreshToken: data.refreshToken,
                pendingMfaToken: null
            });
            modals.close();
            router.navigate('dashboard');
            toast.success('Welcome back!');
        } catch (err) {
            toast.error(err.message || 'Invalid verification code');
        }
    },

    verify2FACode: function(e, method) {
        e.preventDefault();
        const code = e.target.code.value.trim();
        if (code.length !== 6) { toast.error('Please enter a 6-digit code'); return; }
        store.setState({ twoFactorEnabled: true, twoFactorMethod: method });
        // 2FA status is managed server-side via mfa_enabled — no localStorage needed
        toast.success('Two-factor authentication enabled!');
        modals.close();
        renderApp();
    },

    setThemeMode: function(mode) {
        if (mode === 'dark') {
            document.body.classList.add('dark-mode');
            store.setState({ darkMode: true });
            localStorage.setItem('vaultlister_darkmode', 'true');
        } else if (mode === 'light') {
            document.body.classList.remove('dark-mode');
            store.setState({ darkMode: false });
            localStorage.setItem('vaultlister_darkmode', 'false');
        } else {
            // System preference
            const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
            document.body.classList.toggle('dark-mode', prefersDark);
            store.setState({ darkMode: prefersDark });
            localStorage.removeItem('vaultlister_darkmode');
        }
        renderApp(pages.settings());
    },

    setAccentColor: function(color) {
        themeManager.setAccent(color);
        renderApp(pages.settings());
    },

    resetAppearanceToDefaults: function() {
        // Reset theme to light
        document.body.classList.remove('dark-mode');
        store.setState({ darkMode: false });
        localStorage.setItem('vaultlister_darkmode', 'false');

        // Reset accent color to blue (default)
        localStorage.setItem('vaultlister_accent', 'blue');
        themeManager.setAccent('blue');

        // Reset density to default
        localStorage.setItem('vaultlister_density', 'default');
        if (typeof themeManager.setDensity === 'function') {
            themeManager.setDensity('default');
        }

        // Reset font size to default
        localStorage.setItem('vaultlister_fontsize', 'default');
        if (typeof themeManager.setFontSize === 'function') {
            themeManager.setFontSize('default');
        }

        toast.success('Appearance settings reset to defaults');
        renderApp(pages.settings());
    },

