    sendFeatureRequest: async function(e) {
        e.preventDefault();
        const form = e.target;
        const title = form.title.value.trim();
        const category = form.category.value;
        const description = form.description.value.trim();
        const reason = form.reason?.value?.trim() || '';

        if (!title || !description) {
            toast.error('Please fill in the title and description');
            return;
        }

        try {
            await api.ensureCSRFToken();
            await api.post('/feedback', {
                type: 'feature_request',
                category,
                title,
                description: reason ? `${description}\n\nWhy: ${reason}` : description,
                is_anonymous: false
            });
            toast.success('Thank you! Your feature request has been submitted.');
            modals.close();
        } catch (error) {
            toast.error(error.message || 'Failed to submit feature request');
        }
    },

    toggleGettingStartedStep: function(stepId) {
        const key = 'vaultlister_getting_started';
        let saved = {};
        try {
            saved = JSON.parse(localStorage.getItem(key) || '{}');
        } catch (e) {
            console.error('Failed to parse getting started steps:', e);
            saved = {};
        }
        saved[stepId] = !saved[stepId];
        localStorage.setItem(key, JSON.stringify(saved));
        store.setState({ gettingStartedSteps: saved });
        if (saved[stepId]) {
            toast.success('Step marked as complete!');
        } else {
            toast.info('Step marked as incomplete');
        }
        renderApp();
    },

