    downloadCSVTemplate: function() {
        const template = 'title,price,description,category,brand,size,condition,quantity\n"Example Item","29.99","Item description","Clothing","Brand Name","M","New with tags","1"';
        const blob = new Blob([template], { type: 'text/csv' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = 'vaultlister_import_template.csv';
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
        toast.success('Template downloaded!');
    },

    previewCSV: function(event) {
        const file = event.target.files[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = function(e) {
            const text = e.target.result;
            const lines = text.split('\n').filter(line => line.trim());

            if (lines.length < 2) {
                toast.error('CSV file must have a header row and at least one data row');
                return;
            }

            // Parse CSV (simple implementation - doesn't handle quoted commas)
            const rows = lines.map(line => line.split(',').map(cell => cell.trim().replace(/^"|"$/g, '')));
            const headers = rows[0];
            const dataRows = rows.slice(1);

            // Validate required columns
            if (!headers.includes('title') || !headers.includes('price')) {
                toast.error('CSV must have "title" and "price" columns. Please check your file headers.');
                return;
            }

            // Show preview
            const preview = document.getElementById('csv-preview');
            const previewContent = document.getElementById('csv-preview-content');
            const itemCount = document.getElementById('csv-item-count');
            const importBtn = document.getElementById('csv-import-btn');

            let tableHTML = '<table style="width: 100%; border-collapse: collapse; font-size: 13px;"><thead><tr>';
            headers.forEach(header => {
                tableHTML += `<th style="background: var(--gray-100); padding: 8px; text-align: left; border: 1px solid var(--gray-200); font-weight: 600;">${escapeHtml(header)}</th>`;
            });
            tableHTML += '</tr></thead><tbody>';

            dataRows.slice(0, 5).forEach(row => {
                tableHTML += '<tr>';
                row.forEach(cell => {
                    tableHTML += `<td style="padding: 8px; border: 1px solid var(--gray-200);">${escapeHtml(cell)}</td>`;
                });
                tableHTML += '</tr>';
            });
            tableHTML += '</tbody></table>';

            previewContent.innerHTML = tableHTML;
            itemCount.textContent = `Found ${dataRows.length} items${dataRows.length > 5 ? ' (showing first 5)' : ''}`;
            preview.style.display = 'block';
            importBtn.disabled = false;

            // Store parsed data for import
            store.setState({ csvImportData: { headers, rows: dataRows } });
        };

        reader.readAsText(file);
    },

    importCSV: async function() {
        const csvData = store.state.csvImportData;
        if (!csvData) {
            toast.warning('No CSV data to import. Please upload a file first.');
            return;
        }

        const { headers, rows } = csvData;
        const importBtn = document.getElementById('csv-import-btn');
        const originalText = importBtn.innerHTML;

        if (rows.length > 1000) {
            toast.error('Maximum 1000 items per import. Please split your CSV file into smaller batches.');
            return;
        }

        try {
            importBtn.disabled = true;
            importBtn.innerHTML = `${components.icon('upload', 16)} Importing...`;

            // Convert rows to objects
            const items = rows.map(row => {
                const item = {};
                headers.forEach((header, index) => {
                    item[header] = row[index] || '';
                });
                return item;
            });

            await api.ensureCSRFToken();
            const response = await api.post('/inventory/import/csv', { items });

            modals.close();
            toast.success(`Successfully imported ${response.imported} items!`);

            // Reload inventory
            await handlers.loadInventory();
            if (store.state.currentPage === 'inventory') {
                renderApp(pages.inventory());
            }
        } catch (error) {
            console.error('Error importing CSV:', error);
            toast.error('Failed to import CSV. Please check the format and try again.');
        } finally {
            if (importBtn) {
                importBtn.disabled = false;
                importBtn.innerHTML = originalText;
            }
        }
    },

    showListingCharCount: function(inputEl, maxChars) {
        const parent = inputEl.parentElement;
        let counter = parent.querySelector('.char-count');
        if (!counter) {
            counter = document.createElement('div');
            counter.className = 'char-count';
            parent.appendChild(counter);
        }
        const len = inputEl.value.length;
        counter.textContent = len + '/' + maxChars + ' characters';
        counter.style.color = len > maxChars ? 'var(--error)' : len > maxChars * 0.8 ? 'var(--warning-600)' : 'var(--gray-500)';
        counter.style.fontSize = '12px';
        counter.style.marginTop = '4px';
        counter.style.textAlign = 'right';
    },

    // Automations
    loadAutomations: async function() {
        try {
            const data = await api.get('/automations');
            store.setState({ automations: data.rules });
            // Also load run history for failure banner
            try {
                const histData = await api.get('/automations/history?limit=50');
                store.setState({ automationHistoryRuns: histData.runs || [] });
            } catch (histErr) {
                // Non-critical - failure banner just won't show
            }
            // Don't call router.handleRoute() - it creates an infinite loop
            // The router already handles rendering after calling this function
        } catch (error) {
            console.error('Failed to load automations:', error);
            store.setState({ automations: [] });
            toast.error('Failed to load automations');
        }
    },

    // Listings
    loadListings: async function() {
        try {
            const data = await api.get('/listings');
            store.setState({ listings: data.listings || [] });
        } catch (error) {
            console.error('Failed to load listings:', error);
            // Show empty state instead of hanging
            store.setState({ listings: [] });
            toast.error('Failed to load listings. Please check server and refresh.');
        }
    },

    // Switch listings tab and load appropriate data
    switchListingsTab: async function(tab) {
        store.setState({ listingsTab: tab });

        // Load data for the selected tab
        if (tab === 'templates') {
            await this.loadTemplates();
        } else if (tab === 'recently-deleted') {
            await this.loadDeletedItems(true);
        } else if (tab === 'listings' || tab === 'archived') {
            await this.loadListings();
        }

        renderApp(pages.listings());
    },

    filterListings: function(filterType, value) {
        if (filterType === 'status') {
            store.setState({ listingsStatusFilter: value });
        } else if (filterType === 'platform') {
            store.setState({ listingsPlatformFilter: value });
        } else if (filterType === 'folder') {
            store.setState({ listingsFolderFilter: value });
        }

        // Re-render listings page
        if (store.state.currentPage === 'listings') {
            const pageContent = pages.listings();
            document.querySelector('.page-content').innerHTML = pageContent;
        }
    },

    toggleListingDetails: function(listingId) {
        const expandedListings = store.state.expandedListings || [];
        const index = expandedListings.indexOf(listingId);

        if (index > -1) {
            // Already expanded, collapse it
            expandedListings.splice(index, 1);
        } else {
            // Expand it
            expandedListings.push(listingId);
        }

        store.setState({ expandedListings: [...expandedListings] });

        // Re-render listings page
        if (store.state.currentPage === 'listings') {
            const pageContent = pages.listings();
            document.querySelector('.page-content').innerHTML = pageContent;
        }
    },

