    // Batch Ship by Region — groups unshipped orders by state/region
    showBatchShipByRegion: function() {
        const orders = (store.state.orders || []).filter(o => o.status === 'pending' || o.status === 'confirmed');

        if (orders.length === 0) {
            toast.info('No pending orders to batch ship');
            return;
        }

        // Group by state/region from shipping address
        const regions = {};
        orders.forEach(order => {
            const state = order.shipping_state || order.state || order.buyer_state || 'Unknown';
            if (!regions[state]) regions[state] = [];
            regions[state].push(order);
        });

        const sortedRegions = Object.entries(regions).sort((a, b) => b[1].length - a[1].length);

        modals.show(`
            <div class="modal-header">
                <h2>${components.icon('map-pin', 20)} Batch Ship by Region</h2>
                <button class="modal-close" aria-label="Close" onclick="modals.close()">${components.icon('x', 20)}</button>
            </div>
            <div class="modal-body" style="max-height: 60vh; overflow-y: auto;">
                <p class="text-gray-500 mb-4">Orders grouped by shipping region. Select a region to create batch labels.</p>
                ${sortedRegions.map(([state, regionOrders]) => `
                    <div class="card mb-3" style="cursor: pointer;" onclick="this.querySelector('.region-orders').classList.toggle('hidden')">
                        <div class="card-body" style="padding: 12px 16px;">
                            <div class="flex justify-between items-center">
                                <div class="flex items-center gap-2">
                                    ${components.icon('map-pin', 16)}
                                    <span class="font-semibold">${escapeHtml(state)}</span>
                                </div>
                                <div class="flex items-center gap-3">
                                    <span class="badge badge-primary">${regionOrders.length} order${regionOrders.length > 1 ? 's' : ''}</span>
                                    <button class="btn btn-xs btn-primary" onclick="event.stopPropagation(); handlers.batchCreateLabelsForRegion('${escapeHtml(state)}')">
                                        ${components.icon('tag', 12)} Create Labels
                                    </button>
                                </div>
                            </div>
                            <div class="region-orders hidden mt-3" style="border-top: 1px solid var(--gray-200); padding-top: 8px;">
                                ${regionOrders.map(o => `
                                    <div class="flex justify-between items-center py-1 text-sm">
                                        <span>${escapeHtml(o.buyer_username || 'N/A')}</span>
                                        <span>${escapeHtml(o.item_title || 'N/A')}</span>
                                        <span class="font-medium">$${parseFloat(o.sale_price || 0).toFixed(2)}</span>
                                    </div>
                                `).join('')}
                            </div>
                        </div>
                    </div>
                `).join('')}
            </div>
        `);
    },

    batchCreateLabelsForRegion: function(region) {
        const orders = (store.state.orders || []).filter(o =>
            (o.status === 'pending' || o.status === 'confirmed') &&
            (o.shipping_state || o.state || o.buyer_state || 'Unknown') === region
        );

        toast.success(`Creating ${orders.length} shipping labels for ${region}...`);
        modals.close();
        router.navigate('shipping-labels');
    },

    // Order Map Visualization
    showOrderMap: function() {
        const orders = store.state.orders || [];

        if (orders.length === 0) {
            toast.info('No orders to display');
            return;
        }

        // Group by state
        const stateCount = {};
        orders.forEach(order => {
            const state = order.shipping_state || order.state || order.buyer_state || 'Unknown';
            stateCount[state] = (stateCount[state] || 0) + 1;
        });

        const sortedStates = Object.entries(stateCount).sort((a, b) => b[1] - a[1]);
        const maxCount = sortedStates.length > 0 ? sortedStates[0][1] : 1;

        modals.show(`
            <div class="modal-header">
                <h2>${components.icon('map', 20)} Order Delivery Map</h2>
                <button class="modal-close" aria-label="Close" onclick="modals.close()">${components.icon('x', 20)}</button>
            </div>
            <div class="modal-body" style="max-height: 70vh; overflow-y: auto;">
                <p class="text-gray-500 mb-4">Order distribution by shipping destination. Darker bars = more orders.</p>
                <div class="grid grid-cols-3 gap-2 mb-4">
                    <div class="card"><div class="card-body text-center"><div class="text-2xl font-bold">${orders.length}</div><div class="text-xs text-gray-500">Total Orders</div></div></div>
                    <div class="card"><div class="card-body text-center"><div class="text-2xl font-bold">${sortedStates.length}</div><div class="text-xs text-gray-500">Regions</div></div></div>
                    <div class="card"><div class="card-body text-center"><div class="text-2xl font-bold">${sortedStates.length > 0 ? sortedStates[0][0] : '-'}</div><div class="text-xs text-gray-500">Top Region</div></div></div>
                </div>
                <div class="space-y-2">
                    ${sortedStates.map(([state, count]) => {
                        const percent = (count / maxCount * 100).toFixed(0);
                        return `
                            <div class="flex items-center gap-3">
                                <span class="text-sm font-medium" style="min-width: 80px;">${escapeHtml(state)}</span>
                                <div style="flex: 1; background: var(--gray-100); border-radius: 4px; height: 24px; position: relative; overflow: hidden;">
                                    <div style="width: ${percent}%; height: 100%; background: var(--primary-500); border-radius: 4px; transition: width 0.3s;"></div>
                                </div>
                                <span class="text-sm font-bold" style="min-width: 40px; text-align: right;">${count}</span>
                            </div>
                        `;
                    }).join('')}
                </div>
            </div>
        `);
    },

    exportOrdersCSV: function() {
        const orders = store.state.orders || [];

        if (orders.length === 0) {
            toast.warning('No orders to export');
            return;
        }

        // CSV headers
        const headers = ['Date', 'Platform', 'Buyer', 'Item', 'Status', 'Price', 'Tracking', 'Carrier', 'Expected Arrival'];

        // CSV rows
        const rows = orders.map(order => [
            new Date(order.created_at).toLocaleDateString(),
            order.platform || '',
            order.buyer_username || '',
            order.item_title || '',
            order.status || '',
            `$${order.sale_price || 0}`,
            order.tracking_number || '',
            order.shipping_provider || '',
            order.expected_delivery ? new Date(order.expected_delivery).toLocaleDateString() : ''
        ]);

        // Generate CSV content
        const csvContent = [
            headers.join(','),
            ...rows.map(row => row.map(cell => `"${String(cell).replace(/"/g, '""')}"`).join(','))
        ].join('\\n');

        // Download file
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = `orders_${toLocalDate(new Date())}.csv`;
        link.click();
        URL.revokeObjectURL(url);

        toast.success(`Exported ${orders.length} orders to CSV`);
    },

