    switchChartType: function(chartId, type) {
        const chartDisplayModes = { ...store.state.chartDisplayModes, [chartId]: type };
        store.setState({ chartDisplayModes });
        if (store.state.currentPage === 'analytics') {
            renderApp(pages.analytics());
        }
    },

    // Export analytics data to CSV
    exportAnalyticsCSV: function() {
        const sales = store.state.sales || [];

        if (sales.length === 0) {
            toast.error('No sales data to export');
            return;
        }

        // CSV headers
        const headers = ['Date', 'Item', 'Platform', 'Sale Price', 'Item Cost', 'Shipping Cost', 'Platform Fee', 'Net Profit', 'Status'];

        // Convert sales to CSV rows
        const rows = sales.map(s => [
            new Date(s.created_at).toLocaleDateString(),
            `"${(s.listing_title || s.inventory_title || 'N/A').replace(/"/g, '""')}"`,
            s.platform,
            (s.sale_price || 0).toFixed(2),
            (s.item_cost || 0).toFixed(2),
            (s.seller_shipping_cost || s.shipping_cost || 0).toFixed(2),
            (s.platform_fee || 0).toFixed(2),
            (s.net_profit || 0).toFixed(2),
            s.status || 'completed'
        ]);

        // Add summary row
        const totalRevenue = sales.reduce((sum, s) => sum + (s.sale_price || 0), 0);
        const totalCost = sales.reduce((sum, s) => sum + (s.item_cost || 0), 0);
        const totalShipping = sales.reduce((sum, s) => sum + (s.seller_shipping_cost || s.shipping_cost || 0), 0);
        const totalFees = sales.reduce((sum, s) => sum + (s.platform_fee || 0), 0);
        const totalProfit = sales.reduce((sum, s) => sum + (s.net_profit || 0), 0);

        rows.push([]);  // Empty row
        rows.push(['TOTALS', '', '', totalRevenue.toFixed(2), totalCost.toFixed(2), totalShipping.toFixed(2), totalFees.toFixed(2), totalProfit.toFixed(2), '']);

        // Build CSV content
        const csvContent = [headers.join(','), ...rows.map(r => r.join(','))].join('\n');

        // Create and download file
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.setAttribute('href', url);
        link.setAttribute('download', `vaultlister-sales-${toLocalDate(new Date())}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);

        toast.success(`Exported ${sales.length} sales to CSV`);
    },

