    submitShopConnection: async function(event, platform) {
        event.preventDefault();
        const formData = new FormData(event.target);
        const username = formData.get('username');

        if (!username || !username.trim()) {
            toast.error('Please enter a username');
            return;
        }

        try {
            await api.ensureCSRFToken();
            try {
                await api.post('/shops', { platform, username: username.trim() });
            } catch (postErr) {
                // Already connected — update instead
                if (postErr.message && postErr.message.includes('already connected')) {
                    await api.put(`/shops/${platform}`, { username: username.trim(), isConnected: true });
                } else {
                    throw postErr;
                }
            }
            toast.success(`${platform} connected successfully!`);
            modals.close();
            await handlers.loadShops();

            // Force re-render
            if (store.state.currentPage === 'shops') {
                const pageContent = pages.shops();
                document.querySelector('.page-content').innerHTML = pageContent;
            }
        } catch (error) {
            console.error('Shop connection error:', error);
            if (error.message.includes('token') || error.message.includes('Token')) {
                toast.error('Connection failed. Please try logging out and back in.');
            } else if (error.message.includes('network') || error.message.includes('fetch')) {
                toast.error('Network error. Please check your connection.');
            } else {
                toast.error(error.message || 'Failed to connect shop. Please try again.');
            }
        }
    },

    disconnectShop: async function(platform) {
        if (!await modals.confirm(`Disconnect ${platform}?`, { title: 'Disconnect Platform', confirmText: 'Disconnect', danger: true })) return;

        try {
            await api.delete(`/shops/${platform}`);
            toast.success(`${platform} disconnected`);
            await handlers.loadShops();

            // Force page re-render
            if (store.state.currentPage === 'shops') {
                const pageContent = pages.shops();
                document.querySelector('.page-content').innerHTML = pageContent;
            }
        } catch (error) {
            toast.error(error.message);
        }
    },

    connectOAuth: async function(platform) {
        try {
            // Get authorization URL from backend
            const response = await api.get(`/oauth/authorize/${platform}`);

            if (!response || !response.authUrl) {
                // OAuth not configured for this platform - show helpful message
                modals.show(`
                    <div class="modal-header">
                        <h2 class="modal-title">${components.icon('info', 20)} OAuth Not Configured</h2>
                        <button class="modal-close" aria-label="Close" onclick="modals.close()">${components.icon('close')}</button>
                    </div>
                    <div class="modal-body">
                        <div class="p-4 bg-yellow-50 border border-yellow-200 rounded-lg mb-4">
                            <p class="text-yellow-800 mb-2"><strong>OAuth is not yet configured for ${platform}.</strong></p>
                            <p class="text-yellow-700 text-sm">To enable OAuth connections, you'll need to:</p>
                            <ol class="text-yellow-700 text-sm mt-2 ml-4 list-decimal">
                                <li>Register your app with ${platform}'s developer portal</li>
                                <li>Add your OAuth credentials to the .env file</li>
                                <li>Restart the server</li>
                            </ol>
                        </div>
                        <p class="text-gray-600 text-sm">In the meantime, you can use the <strong>Connect Manually</strong> option with your username.</p>
                        <div class="flex justify-end mt-4">
                            <button class="btn btn-secondary" onclick="modals.close()">Close</button>
                        </div>
                    </div>
                `);
                return;
            }

            const { authUrl, state } = response;

            // Open popup window for OAuth flow
            const width = 600;
            const height = 700;
            const left = window.screen.width / 2 - width / 2;
            const top = window.screen.height / 2 - height / 2;

            const popup = window.open(
                authUrl,
                'oauth_popup',
                `width=${width},height=${height},left=${left},top=${top},toolbar=no,menubar=no,location=no,status=no`
            );

            if (!popup) {
                toast.error('Popup blocked - please allow popups for OAuth');
                return;
            }

            // Close modal
            modals.close();

            // Show loading toast
            toast.info('Waiting for authorization...');

            // Listen for OAuth callback via CustomEvent and postMessage
            const handleOAuthResult = async (detail) => {
                if (detail.platform === platform || !detail.platform) {
                    window.removeEventListener('oauthComplete', customEventHandler);
                    window.removeEventListener('message', messageHandler);

                    if (detail.success) {
                        toast.success(`${platform} connected successfully!`);
                        await handlers.loadShops();

                        if (store.state.currentPage === 'shops') {
                            const pageContent = pages.shops();
                            document.querySelector('.page-content').innerHTML = pageContent;
                        }
                    } else {
                        toast.error(detail.error || 'OAuth connection failed');
                    }
                }
            };
            const customEventHandler = (event) => handleOAuthResult(event.detail);
            const messageHandler = (event) => {
                if (event.data && event.data.type === 'oauthComplete') handleOAuthResult(event.data);
            };
            window.addEventListener('oauthComplete', customEventHandler);
            window.addEventListener('message', messageHandler);

        } catch (error) {
            console.error('OAuth error:', error);
            // Show a more helpful modal instead of just an error toast
            modals.show(`
                <div class="modal-header">
                    <h2 class="modal-title">${components.icon('alert-circle', 20)} OAuth Connection Issue</h2>
                    <button class="modal-close" aria-label="Close" onclick="modals.close()">${components.icon('close')}</button>
                </div>
                <div class="modal-body">
                    <div class="p-4 bg-red-50 border border-red-200 rounded-lg mb-4">
                        <p class="text-red-800 mb-2"><strong>Unable to connect via OAuth</strong></p>
                        <p class="text-red-700 text-sm">This could be because:</p>
                        <ul class="text-red-700 text-sm mt-2 ml-4 list-disc">
                            <li>OAuth credentials are not configured for ${platform}</li>
                            <li>The platform's API may be temporarily unavailable</li>
                            <li>Network connectivity issues</li>
                        </ul>
                    </div>
                    <p class="text-gray-600 text-sm mb-4">You can try the <strong>Connect Manually</strong> option instead, or check your OAuth configuration in the .env file.</p>
                    <div class="flex justify-end gap-2">
                        <button class="btn btn-secondary" onclick="modals.close()">Close</button>
                        <button class="btn btn-primary" onclick="modals.close(); handlers.connectShop('${platform}')">Try Manual Connection</button>
                    </div>
                </div>
            `);
        }
    },

