    // Mark settings as changed
    markSettingsChanged: function() {
        store.setState({ settingsChanged: true });
        // Enable the save button
        const saveBtn = document.getElementById('settings-save-btn');
        if (saveBtn) {
            saveBtn.disabled = false;
            saveBtn.classList.remove('btn-disabled');
        }
    },

    // Save settings changes
    saveSettings: async function() {
        // Build summary of what changed
        const changes = [];
        const fullName = document.getElementById('settings-full-name');
        if (fullName && fullName.value !== (store.state.user?.full_name || '')) {
            changes.push('Full Name: "' + fullName.value + '"');
        }
        const timezone = document.getElementById('settings-timezone');
        if (timezone && timezone.value !== (store.state.userTimezone || Intl.DateTimeFormat().resolvedOptions().timeZone)) {
            changes.push('Timezone: ' + timezone.options[timezone.selectedIndex]?.text);
        }
        const darkModeToggle = document.getElementById('dark-mode-toggle');
        if (darkModeToggle) {
            const currentDark = store.state.darkMode || false;
            if (darkModeToggle.checked !== currentDark) {
                changes.push('Dark Mode: ' + (darkModeToggle.checked ? 'Enabled' : 'Disabled'));
            }
        }

        // If we detected specific changes, show them; otherwise generic message
        const summary = changes.length > 0
            ? changes.map(c => '\u2022 ' + c).join('\n')
            : '\u2022 Settings modified';

        if (!await modals.confirm('Save these changes?\n\n' + summary, { title: 'Save Settings', confirmText: 'Save' })) {
            return;
        }

        // Actually save
        if (darkModeToggle) {
            const darkModeEnabled = darkModeToggle.checked;
            store.setState({ darkMode: darkModeEnabled, settingsChanged: false });
            localStorage.setItem('vaultlister_dark_mode', darkModeEnabled ? 'true' : 'false');
            delete store.state.darkModePreview;
        }
        if (fullName) {
            const user = store.state.user || {};
            user.full_name = fullName.value;
            store.setState({ user });
        }
        if (timezone) {
            store.setState({ userTimezone: timezone.value });
            localStorage.setItem('vaultlister_timezone', timezone.value);
        }

        store.setState({ settingsChanged: false });
        toast.success('Settings saved successfully');

        // Disable the save button after saving
        const saveBtn = document.getElementById('settings-save-btn');
        if (saveBtn) {
            saveBtn.disabled = true;
            saveBtn.classList.add('btn-disabled');
            // Feature 1: Settings Save Confirmation Animation
            saveBtn.classList.add('settings-save-success');
            setTimeout(() => {
                if (saveBtn) {
                    saveBtn.classList.remove('settings-save-success');
                }
            }, 600);
        }
    },

    // Account Activity Log handlers
    revokeSession: async function(sessionId) {
        if (!await modals.confirm('Revoke this session? The user will be logged out.', { danger: true })) return;

        try {
            await api.ensureCSRFToken();
            await api.delete('/auth/sessions/' + sessionId);
        } catch (err) {
            toast.error('Failed to revoke session');
            return;
        }

        const activityLog = store.state.accountActivityLog || [];
        const updatedLog = activityLog.filter(a => a.id !== sessionId && a.timestamp !== sessionId);
        store.setState({ accountActivityLog: updatedLog });
        toast.success('Session revoked successfully');
        renderApp(pages.settings());
    },

    revokeAllSessions: async function() {
        if (!await modals.confirm('Sign out all other sessions? Only your current session will remain active.', { danger: true })) return;

        try {
            await api.ensureCSRFToken();
            await api.post('/auth/sessions/revoke-all', { refreshToken: store.state.refreshToken });
        } catch (err) {
            toast.error('Failed to revoke sessions');
            return;
        }

        const activityLog = store.state.accountActivityLog || [];
        const currentSession = activityLog.find(a => a.current);
        store.setState({ accountActivityLog: currentSession ? [currentSession] : [] });
        toast.success('All other sessions have been signed out');
        renderApp(pages.settings());
    },

