    // Password strength checker
    checkPasswordStrength: function(value) {
        const meter = document.getElementById('password-strength-meter');
        const bar = document.getElementById('password-strength-bar');
        const label = document.getElementById('password-strength-label');
        if (!meter || !bar || !label) return;

        if (!value || value.length === 0) {
            meter.style.display = 'none';
            return;
        }
        meter.style.display = 'block';

        let score = 0;
        if (value.length >= 8) score++;
        if (value.length >= 12) score++;
        if (/[A-Z]/.test(value)) score++;
        if (/[a-z]/.test(value)) score++;
        if (/[0-9]/.test(value)) score++;
        if (/[^A-Za-z0-9]/.test(value)) score++;

        const levels = [
            { max: 1, width: '16%', color: 'var(--danger, #ef4444)', text: 'Weak' },
            { max: 2, width: '33%', color: '#f97316', text: 'Fair' },
            { max: 3, width: '50%', color: '#eab308', text: 'Good' },
            { max: 4, width: '75%', color: '#84cc16', text: 'Strong' },
            { max: 6, width: '100%', color: 'var(--success, #22c55e)', text: 'Very Strong' },
        ];
        const level = levels.find(l => score <= l.max) || levels[levels.length - 1];
        bar.style.width = level.width;
        bar.style.background = level.color;
        label.textContent = level.text;
        label.style.color = level.color;
    },

    // Change password handler
    changePassword: async function() {
        const currentPw = document.getElementById('account-current-password')?.value;
        const newPw = document.getElementById('account-new-password')?.value;
        const confirmPw = document.getElementById('account-confirm-password')?.value;

        if (!currentPw || !newPw || !confirmPw) {
            toast.error('Please fill in all password fields');
            return;
        }
        if (newPw.length < 12) {
            toast.error('New password must be at least 12 characters');
            return;
        }
        if (newPw !== confirmPw) {
            toast.error('New passwords do not match');
            return;
        }

        try {
            const result = await api.put('/auth/password', {
                currentPassword: currentPw,
                newPassword: newPw
            });

            if (result.error) {
                toast.error(result.error);
                return;
            }

            // Clear fields after successful change
            document.getElementById('account-current-password').value = '';
            document.getElementById('account-new-password').value = '';
            document.getElementById('account-confirm-password').value = '';
            toast.success('Password updated successfully');
        } catch (err) {
            toast.error(err.message || 'Failed to change password');
        }
    },

