    applyAIResults: function() {
        if (!this._aiGeneratedData) {
            return toast.error('No AI results to apply');
        }

        // Get values from AI results before closing the modal
        const title = document.getElementById('ai-result-title')?.value;
        const description = document.getElementById('ai-result-description')?.value;
        const brand = document.getElementById('ai-result-brand')?.value;
        const category = document.getElementById('ai-result-category')?.value;
        const color = document.getElementById('ai-result-color')?.value;
        const condition = document.getElementById('ai-result-condition')?.value;
        const size = document.getElementById('ai-result-size')?.value;
        const tags = document.getElementById('ai-result-tags')?.value;
        const price = document.getElementById('ai-result-price')?.value;

        // Store the data for after modal opens
        const formData = { title, description, brand, category, color, condition, size, tags, price };

        // Close wizard modal
        modals.close();

        // Wait for modal to close, then open Add Item modal and populate with retry
        setTimeout(() => {
            // Open the Add Item modal
            modals.addItem();

            // Retry finding the form up to 5 times with increasing delays
            let attempts = 0;
            const maxAttempts = 5;
            const tryPopulate = () => {
                attempts++;
                const form = document.getElementById('add-item-form');
                if (form) {
                    this._populateAddItemForm(formData);
                    toast.success('AI results applied to form!');
                } else if (attempts < maxAttempts) {
                    setTimeout(tryPopulate, 100 * attempts);
                } else {
                    toast.error('Could not apply AI results. Please try again or enter details manually.');
                }
            };
            setTimeout(tryPopulate, 150);
        }, 100);
    },

    _populateAddItemForm: function(data) {
        const form = document.getElementById('add-item-form');
        if (!form) return;

        if (data.title) {
            const titleInput = form.querySelector('[name="title"]');
            if (titleInput) titleInput.value = data.title;
        }

        if (data.description) {
            const descInput = form.querySelector('[name="description"]');
            if (descInput) descInput.value = data.description;
        }

        if (data.brand) {
            const brandInput = form.querySelector('[name="brand"]');
            if (brandInput) brandInput.value = data.brand;
        }

        if (data.category) {
            const categoryInput = form.querySelector('[name="category"]');
            if (categoryInput) categoryInput.value = data.category;
        }

        if (data.color) {
            const colorInput = form.querySelector('[name="color"]');
            if (colorInput) colorInput.value = data.color;
        }

        if (data.condition) {
            const conditionInput = form.querySelector('[name="condition"]');
            if (conditionInput) conditionInput.value = data.condition;
        }

        if (data.size) {
            const sizeInput = form.querySelector('[name="size"]');
            if (sizeInput) sizeInput.value = data.size;
        }

        if (data.tags) {
            const tagsInput = form.querySelector('[name="tags"]');
            if (tagsInput) tagsInput.value = data.tags;
        }

        if (data.price) {
            const priceInput = form.querySelector('[name="listPrice"]');
            if (priceInput) priceInput.value = data.price;
        }
    },

    submitAdvancedCrosslist: async function(event, itemIds) {
        event.preventDefault();
        const form = event.target;
        const formData = new FormData(form);

        const workflowMode = formData.get('workflowMode');
        const selectedPlatforms = formData.getAll('platforms');

        if (selectedPlatforms.length === 0) {
            return toast.warning('Please select at least one platform');
        }

        const ids = itemIds.split(',');
        const listings = [];

        try {
            await api.ensureCSRFToken();

            if (workflowMode === 'unified') {
                // Unified mode: same listing for all platforms
                const baseTitle = formData.get('baseTitle');
                const baseDescription = formData.get('baseDescription');
                const basePrice = parseFloat(formData.get('basePrice'));
                const baseShipping = formData.get('baseShipping');
                const baseTags = formData.get('baseTags') ? formData.get('baseTags').split(',').map(t => t.trim()).filter(Boolean) : [];

                for (const itemId of ids) {
                    for (const platform of selectedPlatforms) {
                        listings.push({
                            inventory_id: itemId,
                            platform,
                            title: baseTitle,
                            description: baseDescription,
                            price: basePrice,
                            shipping: baseShipping,
                            tags: baseTags
                        });
                    }
                }
            } else {
                // Customized mode: platform-specific listings
                for (const itemId of ids) {
                    for (const platform of selectedPlatforms) {
                        const title = formData.get(`${platform}Title`);
                        const description = formData.get(`${platform}Description`);
                        const price = parseFloat(formData.get(`${platform}Price`));
                        const tags = formData.get(`${platform}Tags`) ? formData.get(`${platform}Tags`).split(',').map(t => t.trim()).filter(Boolean) : [];

                        listings.push({
                            inventory_id: itemId,
                            platform,
                            title,
                            description,
                            price,
                            tags
                        });
                    }
                }
            }

            // Submit batch listing creation
            await api.post('/listings/batch', { listings });

            toast.success(`Created ${listings.length} listings across ${selectedPlatforms.length} platform(s)!`);
            modals.close();
            await handlers.loadListings();

            // Clear selection
            store.setState({ crosslistSelectedItems: [] });

            // Navigate to listings page
            router.navigate('listings');
        } catch (error) {
            // Retry once if CSRF error
            if (error.message && error.message.includes('CSRF')) {
                try {
                    await api.ensureCSRFToken(true); // Force refresh token
                    await api.post('/listings/batch', { listings });

                    toast.success(`Created ${listings.length} listings across ${selectedPlatforms.length} platform(s)!`);
                    modals.close();
                    await handlers.loadListings();
                    store.setState({ crosslistSelectedItems: [] });
                    router.navigate('listings');
                } catch (retryError) {
                    toast.error('CSRF validation failed. Please refresh the page and try again.');
                }
            } else {
                toast.error(error.message);
            }
        }
    },

