    // Create and start batch photo job
    startBatchPhotoJob: async function() {
        const selectedImages = store.state.batchPhotoSelectedImages || [];
        if (selectedImages.length === 0) {
            toast.warning('No images selected');
            return;
        }

        try {
            modals.close();
            store.setState({ batchPhotoModalOpen: false });

            toast.info(`Creating batch job for ${selectedImages.length} image(s)...`);

            await api.ensureCSRFToken();

            // Create the job
            const result = await api.post('/batch-photo/jobs', {
                name: `Batch ${new Date().toLocaleString()}`,
                image_ids: selectedImages,
                transformations: store.state.batchPhotoTransformations
            });

            const jobId = result.id;
            toast.success('Batch job created, starting processing...');

            // Start the job
            await api.post(`/batch-photo/jobs/${jobId}/start`, {});

            // Load jobs and start polling
            await handlers.loadBatchPhotoJobs();

            // Poll for progress every 2 seconds
            handlers.pollBatchPhotoProgress(jobId);

            // Clear batch selection
            store.setState({
                batchPhotoSelectedImages: [],
                selectedImages: []
            });

            render();
        } catch (error) {
            toast.error('Failed to start batch job: ' + error.message);
            console.error('Batch job error:', error);
        }
    },

    // Poll batch photo job progress
    pollBatchPhotoProgress: function(jobId) {
        // Clear previous interval if exists
        if (store.state.batchPhotoActivePollInterval) {
            clearInterval(store.state.batchPhotoActivePollInterval);
        }

        const pollInterval = setInterval(async () => {
            try {
                const job = await api.get(`/batch-photo/jobs/${jobId}`);

                store.setState({ batchPhotoProgress: job });

                // Update jobs list
                const jobs = store.state.batchPhotoJobs || [];
                const jobIndex = jobs.findIndex(j => j.id === jobId);
                if (jobIndex !== -1) {
                    jobs[jobIndex] = job;
                    store.setState({ batchPhotoJobs: [...jobs] });
                }

                // Check if job is complete
                if (job.status === 'completed' || job.status === 'failed') {
                    clearInterval(pollInterval);
                    store.setState({ batchPhotoActivePollInterval: null });

                    if (job.status === 'completed') {
                        toast.success(`Batch job complete! Processed ${job.processed}/${job.total} images`);
                    } else {
                        toast.error(`Batch job failed. Processed ${job.processed}, Failed ${job.failed}`);
                    }

                    render();
                } else if (job.status === 'processing') {
                    render();
                }
            } catch (error) {
                console.error('Failed to poll batch job progress:', error);
                clearInterval(pollInterval);
                store.setState({ batchPhotoActivePollInterval: null });
            }
        }, 2000);  // Poll every 2 seconds

        store.setState({ batchPhotoActivePollInterval: pollInterval });
    },

    // Cancel batch photo job
    cancelBatchPhotoJob: async function(jobId) {
        if (!await modals.confirm('Cancel this batch job?', { title: 'Cancel Job', confirmText: 'Cancel Job', danger: true })) return;

        try {
            await api.ensureCSRFToken();
            await api.post(`/batch-photo/jobs/${jobId}/cancel`, {});

            // Clear polling interval
            if (store.state.batchPhotoActivePollInterval) {
                clearInterval(store.state.batchPhotoActivePollInterval);
                store.setState({ batchPhotoActivePollInterval: null });
            }

            toast.success('Batch job cancelled');
            await handlers.loadBatchPhotoJobs();
            render();
        } catch (error) {
            toast.error('Failed to cancel batch job: ' + error.message);
        }
    },

    // Delete batch photo job
    deleteBatchPhotoJob: async function(jobId) {
        if (!await modals.confirm('Delete this batch job? This cannot be undone.', { title: 'Delete Job', confirmText: 'Delete', danger: true })) return;

        try {
            await api.ensureCSRFToken();
            await api.delete(`/batch-photo/jobs/${jobId}`);

            toast.success('Batch job deleted');
            await handlers.loadBatchPhotoJobs();
            render();
        } catch (error) {
            toast.error('Failed to delete batch job: ' + error.message);
        }
    },

