    // Debounced text filter for transactions — re-renders after typing stops
    _txSearchTimer: null,
    debouncedTxFilter: function(field, value) {
        store.setState({ [field]: value });
        handlers.saveTxFilters();
        clearTimeout(handlers._txSearchTimer);
        handlers._txSearchTimer = setTimeout(() => {
            const focusedId = document.activeElement?.dataset?.txFilter;
            const cursorPos = document.activeElement?.selectionStart;
            renderApp(pages.transactions());
            // Restore focus to the input after re-render
            if (focusedId) {
                const el = document.querySelector(`[data-tx-filter="${focusedId}"]`);
                if (el) {
                    el.focus();
                    if (typeof cursorPos === 'number') {
                        el.setSelectionRange(cursorPos, cursorPos);
                    }
                }
            }
        }, 300);
    },

    loadTxFiltersFromStorage: function() {
        const savedFilters = localStorage.getItem('vaultlister_tx_filters');
        if (savedFilters) {
            try {
                const filters = JSON.parse(savedFilters);
                store.setState(filters);
            } catch (e) {
                console.error('Failed to load transaction filters:', e);
            }
        }
    },

