    // Show Quick Location Picker modal
    showQuickLocationPicker: function(mode) {
        const savedLocations = store.state.savedLocations || [
            { location: 'Warehouse A', bin: 'A1-01-A' },
            { location: 'Warehouse A', bin: 'A1-01-B' },
            { location: 'Warehouse A', bin: 'A1-02-A' },
            { location: 'Warehouse B', bin: 'B1-01-A' },
            { location: 'Storage Room', bin: 'S1-01' },
            { location: 'Storage Room', bin: 'S1-02' }
        ];

        // Group by location
        const grouped = savedLocations.reduce((acc, loc) => {
            if (!acc[loc.location]) acc[loc.location] = [];
            acc[loc.location].push(loc.bin);
            return acc;
        }, {});

        const html = `
            <div class="location-picker-dropdown" style="position: absolute; top: 100%; left: 0; z-index: 1000; background: var(--bg-primary); border: 1px solid var(--gray-200); border-radius: var(--radius-md); box-shadow: var(--shadow-lg); padding: 12px; min-width: 280px; max-height: 300px; overflow-y: auto;">
                <div class="text-sm font-medium mb-2" style="color: var(--text-primary);">Quick Select Location</div>
                ${Object.entries(grouped).map(([location, bins]) => `
                    <div class="mb-2">
                        <div class="text-xs font-semibold text-gray-500 mb-1">${escapeHtml(location)}</div>
                        <div class="flex flex-wrap gap-1">
                            ${bins.map(bin => `
                                <button type="button" class="btn btn-xs btn-secondary" onclick="handlers.selectLocation('${mode}', '${escapeHtml(location)}', '${escapeHtml(bin)}')">
                                    ${escapeHtml(bin)}
                                </button>
                            `).join('')}
                        </div>
                    </div>
                `).join('')}
                <div class="border-t pt-2 mt-2" style="border-color: var(--gray-200);">
                    <button type="button" class="btn btn-xs btn-outline w-full" onclick="handlers.openLocationManager()">
                        ${components.icon('settings', 12)} Manage Locations
                    </button>
                </div>
            </div>
        `;

        // Find the location section and append dropdown
        const locationSection = document.querySelector(`#${mode}-item-location`)?.closest('.form-group');
        if (locationSection) {
            // Remove existing dropdown if any
            const existing = locationSection.querySelector('.location-picker-dropdown');
            if (existing) {
                existing.remove();
                return;
            }
            locationSection.style.position = 'relative';
            locationSection.insertAdjacentHTML('beforeend', html);

            // Close on outside click
            const closeHandler = (e) => {
                if (!locationSection.contains(e.target)) {
                    locationSection.querySelector('.location-picker-dropdown')?.remove();
                    document.removeEventListener('click', closeHandler);
                }
            };
            setTimeout(() => document.addEventListener('click', closeHandler), 0);
        }
    },

    // Select a location from the picker
    selectLocation: function(mode, location, bin) {
        const locationInput = document.getElementById(`${mode}-item-location`);
        const binInput = document.getElementById(`${mode}-item-bin`);

        if (locationInput) locationInput.value = location;
        if (binInput) binInput.value = bin;

        // Close the dropdown
        const dropdown = document.querySelector('.location-picker-dropdown');
        if (dropdown) dropdown.remove();

        toast.success(`Location set to ${location} - ${bin}`);
    },

