    // Add a new warehouse location
    addWarehouseLocation: function() {
        const locationName = document.getElementById('new-location-name')?.value?.trim();
        const binName = document.getElementById('new-bin-name')?.value?.trim();

        if (!locationName || !binName) {
            toast.error('Please enter both location and bin name');
            return;
        }

        const savedLocations = store.state.savedLocations || [];
        savedLocations.push({ location: locationName, bin: binName });
        store.setState({ savedLocations });

        // Save to localStorage
        try {
            localStorage.setItem('vl_warehouse_locations', JSON.stringify(savedLocations));
        } catch (e) {
            console.warn('Failed to save warehouse locations:', e);
        }

        // Refresh the modal
        this.openLocationManager();
        toast.success('Location added');
    },

    // Remove a warehouse location
    removeWarehouseLocation: function(index) {
        const savedLocations = store.state.savedLocations || [];
        savedLocations.splice(index, 1);
        store.setState({ savedLocations });

        // Save to localStorage
        try {
            localStorage.setItem('vl_warehouse_locations', JSON.stringify(savedLocations));
        } catch (e) {
            console.warn('Failed to save warehouse locations:', e);
        }

        // Refresh the modal
        this.openLocationManager();
        toast.info('Location removed');
    },

