    // Show Privacy Data Export Modal
    showPrivacyDataExport: async function() {
        modals.show(`
            <div class="modal-header"><h3>Download My Data</h3><button class="modal-close" aria-label="Close" onclick="modals.close()">&times;</button></div>
            <div class="modal-body">
                <p style="margin-bottom: 16px;">Download all your personal data in JSON format. This includes listings, sales, account info, and preferences.</p>
                <button class="btn btn-primary" style="width: 100%; margin-bottom: 8px;" onclick="handlers.downloadDataExport()">
                    ${components.icon('download', 16)} Download My Data
                </button>
                <p style="font-size: 12px; color: var(--text-secondary); margin-top: 12px;">Your data will be prepared and automatically downloaded as data_export.json</p>
            </div>
        `);
    },

    downloadDataExport: async function() {
        try {
            toast.info('Preparing your data export...');
            const res = await fetch('/api/legal/privacy/data-export', {
                headers: { 'Authorization': `Bearer ${store.state.token}` }
            });
            if (!res.ok) { toast.error('Failed to export data'); return; }
            const data = await res.json();
            const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = 'data_export.json';
            a.click();
            URL.revokeObjectURL(url);
            toast.success('Data exported successfully');
        } catch (err) { toast.error('Export failed: ' + err.message); }
    },

