    createLandingPage: async function() {
        const slug = document.getElementById('landing-slug')?.value;
        const title = document.getElementById('landing-title')?.value;
        const description = document.getElementById('landing-desc')?.value;
        if (!slug || !title) { toast.error('Slug and title required'); return; }
        try {
            await api.post('/affiliate/landing-pages', { slug, title, description });
            toast.success('Landing page created');
            modals.close();
            handlers.showAffiliateLandingPages();
        } catch (err) { toast.error('Failed to create landing page'); }
    },

    editLandingPage: async function(pageId) {
        try {
            const pages = await api.get('/affiliate/landing-pages');
            const page = (pages.landing_pages || []).find(p => p.id === pageId);
            if (!page) { toast.error('Landing page not found'); return; }
            modals.show(`
                <div class="modal-header"><h3>Edit Landing Page</h3><button class="modal-close" aria-label="Close" onclick="modals.close()">&times;</button></div>
                <div class="modal-body">
                    <div style="display: grid; gap: 12px;">
                        <div class="form-group">
                            <label class="form-label">Page Slug</label>
                            <input type="text" id="edit-landing-slug" class="form-input" value="${escapeHtml(page.slug || '')}">
                            <span class="form-hint">URL: vaultlister.com/${escapeHtml(page.slug || '')}</span>
                        </div>
                        <div class="form-group">
                            <label class="form-label">Page Title</label>
                            <input type="text" id="edit-landing-title" class="form-input" value="${escapeHtml(page.title || '')}">
                        </div>
                        <div class="form-group">
                            <label class="form-label">Description</label>
                            <textarea id="edit-landing-desc" class="form-input" style="resize: vertical; min-height: 100px;">${escapeHtml(page.description || '')}</textarea>
                        </div>
                    </div>
                    <button class="btn btn-primary" style="width: 100%; margin-top: 16px;" onclick="handlers.saveLandingPage('${pageId}')">
                        Save Changes
                    </button>
                </div>
            `);
        } catch (err) { toast.error('Failed to load landing page'); }
    },

    saveLandingPage: async function(pageId) {
        const slug = document.getElementById('edit-landing-slug')?.value;
        const title = document.getElementById('edit-landing-title')?.value;
        const description = document.getElementById('edit-landing-desc')?.value;
        if (!slug || !title) { toast.error('Slug and title required'); return; }
        try {
            await api.put('/affiliate/landing-pages/' + pageId, { slug, title, description });
            toast.success('Landing page updated');
            modals.close();
            handlers.showAffiliateLandingPages();
        } catch (err) { toast.error('Failed to update landing page'); }
    },

    deleteLandingPage: async function(pageId) {
        if (!await modals.confirm('Delete this landing page?', { title: 'Delete Landing Page', confirmText: 'Delete', danger: true })) return;
        try {
            const res = await fetch(`/api/affiliate/landing-pages/${pageId}`, {
                method: 'DELETE',
                headers: { 'Authorization': `Bearer ${store.state.token}`, 'X-CSRF-Token': api.csrfToken || '' }
            });
            if (!res.ok) throw new Error('Failed to delete landing page');
            toast.success('Landing page deleted');
            handlers.showAffiliateLandingPages();
        } catch (err) { toast.error('Failed to delete landing page'); }
    },

