    // ============================================
    // Recently Deleted (Trash) Handlers
    // ============================================

    async loadDeletedItems(skipRender = false) {
        try {
            const params = new URLSearchParams();
            if (store.state.deletedItemTypeFilter) params.append('type', store.state.deletedItemTypeFilter);
            if (store.state.deletedReasonFilter) params.append('reason', store.state.deletedReasonFilter);
            if (store.state.deletedSearchTerm) params.append('search', store.state.deletedSearchTerm);

            const data = await api.get(`/recently-deleted?${params.toString()}`);
            store.setState({ deletedItems: data.items || [] });
            if (!skipRender) renderApp(pages.recentlyDeleted());
        } catch (err) {
            store.setState({ deletedItems: [] });
            if (!skipRender) renderApp(pages.recentlyDeleted());
            toast.error('Failed to load deleted items');
            console.error(err);
        }
    },

    async restoreDeletedItem(id) {
        try {
            await api.post(`/recently-deleted/${id}/restore`, {});
            toast.success('Item restored successfully');
            await this.loadDeletedItems();
        } catch (err) {
            toast.error('Failed to restore item');
            console.error(err);
        }
    },

    async permanentlyDelete(id) {
        if (!await modals.confirm('Permanently delete this item? This cannot be undone.', { title: 'Permanent Delete', confirmText: 'Delete Forever', danger: true })) return;

        try {
            await api.delete(`/recently-deleted/${id}`);
            toast.success('Item deleted permanently');
            await this.loadDeletedItems();
        } catch (err) {
            toast.error('Failed to delete item');
            console.error(err);
        }
    },

    async bulkRestoreDeleted() {
        const ids = store.state.selectedDeletedIds || [];
        if (ids.length === 0) return toast.warning('No items selected');

        try {
            await api.post('/recently-deleted/bulk-restore', { ids });
            toast.success(`${ids.length} item(s) restored`);
            store.setState({ selectedDeletedIds: [] });
            await this.loadDeletedItems();
        } catch (err) {
            toast.error('Failed to restore items');
            console.error(err);
        }
    },

    async bulkPermanentlyDelete() {
        const ids = store.state.selectedDeletedIds || [];
        if (ids.length === 0) return toast.warning('No items selected');

        if (!await modals.confirm(`Permanently delete ${ids.length} item(s)? This cannot be undone.`, { title: 'Permanent Delete', confirmText: 'Delete Forever', danger: true })) return;

        try {
            await api.delete('/recently-deleted/bulk-delete', { ids });
            toast.success(`${ids.length} item(s) deleted permanently`);
            store.setState({ selectedDeletedIds: [] });
            await this.loadDeletedItems();
        } catch (err) {
            toast.error('Failed to delete items');
            console.error(err);
        }
    },

    async cleanupOldDeleted() {
        if (!await modals.confirm('Permanently delete all items deleted more than 30 days ago?', { title: 'Cleanup Old Items', confirmText: 'Delete All', danger: true })) return;

        try {
            await api.post('/recently-deleted/cleanup', {});
            toast.success('Cleanup complete');
            await this.loadDeletedItems();
        } catch (err) {
            toast.error('Failed to cleanup old deleted items');
            console.error(err);
        }
    },

    setDeletedItemTypeFilter(type) {
        store.setState({ deletedItemTypeFilter: type });
        this.loadDeletedItems();
    },

    setDeletedReasonFilter(reason) {
        store.setState({ deletedReasonFilter: reason });
        this.loadDeletedItems();
    },

    setDeletedSearchTerm(term) {
        store.setState({ deletedSearchTerm: term });
        this.loadDeletedItems();
    },

    toggleSelectDeletedItem(id, checked) {
        let selected = store.state.selectedDeletedIds || [];
        if (checked) {
            if (!selected.includes(id)) selected.push(id);
        } else {
            selected = selected.filter(sid => sid !== id);
        }
        store.setState({ selectedDeletedIds: selected });
        renderApp(pages.recentlyDeleted());
    },

    toggleSelectAllDeleted(checked) {
        const items = store.state.deletedItems || [];
        if (checked) {
            store.setState({ selectedDeletedIds: items.map(i => i.id) });
        } else {
            store.setState({ selectedDeletedIds: [] });
        }
        renderApp(pages.recentlyDeleted());
    },

